INSERT INTO calendar (title, start_date, end_date, applicant_id, approval_id) VALUES ((SELECT title FROM approval WHERE approval_id = #{approvalId}), (SELECT start_date FROM approval WHERE approval_id = #{approvalId}), (SELECT end_date FROM approval WHERE approval_id = #{approvalId}), (SELECT applicant_id FROM approval WHERE approval_id = #{approvalId}), #{approvalId})
